namespace sv_56d51fcb13ee405191ac0048db2c5982.Services;

/// <summary>
/// Scoped service holding the current warehouse selection for a single user circuit.
/// Each SignalR circuit (browser tab) gets its own instance, so managers don't interfere.
/// </summary>
public sealed class WarehouseState
{
    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];

    public string CurrentWarehouseId { get; private set; } = AvailableWarehouses[0].Id;
    public string CurrentWarehouseName { get; private set; } = AvailableWarehouses[0].Name;

    public event Action? OnChanged;

    public void SetWarehouse(string id, string name)
    {
        if (id == CurrentWarehouseId) return;
        CurrentWarehouseId = id;
        CurrentWarehouseName = name;
        OnChanged?.Invoke();
    }
}

namespace sv_56d51fcb13ee405191ac0048db2c5982.Services;

/// <summary>
/// Scoped service that simulates low-stock queries and broadcasts alert count changes
/// to all subscribed components within the same circuit.
/// </summary>
public sealed class InventoryAlertService
{
    private static readonly Random s_random = new();

    public int LastLowStockCount { get; private set; }

    public event Action? OnAlertCountChanged;

    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = s_random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Called by the polling component to publish a new count to every subscriber.
    /// </summary>
    public void PublishAlertCount(int count)
    {
        LastLowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }
}

