@rendermode InteractiveServer
@using sv_56d51fcb13ee405191ac0048db2c5982.Services
@inject WarehouseState WarehouseState
@implements IDisposable

<div class="warehouse-selector px-3 py-2">
    <label class="form-label text-white-50 mb-1 small">Current Warehouse</label>
    <select class="form-select form-select-sm" value="@WarehouseState.CurrentWarehouseId"
            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChanged += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? WarehouseState.AvailableWarehouses[0].Id;
        var name = WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == id).Name ?? "Unknown";
        WarehouseState.SetWarehouse(id, name);
    }

    public void Dispose()
    {
        WarehouseState.OnChanged -= StateHasChanged;
    }
}

@rendermode InteractiveServer
@using sv_56d51fcb13ee405191ac0048db2c5982.Services
@inject InventoryAlertService AlertService
@implements IDisposable

@if (AlertService.LastLowStockCount > 0)
{
    <span class="badge bg-danger rounded-pill ms-auto">@AlertService.LastLowStockCount</span>
}

@code {
    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
    }
}

@page "/dashboard"
@rendermode InteractiveServer
@using sv_56d51fcb13ee405191ac0048db2c5982.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="text-muted">Monitoring: <strong>@WarehouseState.CurrentWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card @(lowStockCount > 0 ? "border-danger" : "border-success")">
            <div class="card-body text-center">
                <h5 class="card-title">Low-Stock Alerts</h5>
                <p class="display-4 @(lowStockCount > 0 ? "text-danger" : "text-success")">
                    @lowStockCount
                </p>
                <p class="text-muted small">
                    Items below minimum level
                </p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Selected Warehouse</h5>
                <p class="display-6">@WarehouseState.CurrentWarehouseName</p>
                <p class="text-muted small">ID: @WarehouseState.CurrentWarehouseId</p>
            </div>
        </div>
    </div>

    <div class="col-md-4">
        <div class="card">
            <div class="card-body text-center">
                <h5 class="card-title">Polling Status</h5>
                <p class="display-6">
                    @if (isPolling)
                    {
                        <span class="text-success">● Active</span>
                    }
                    else
                    {
                        <span class="text-secondary">○ Stopped</span>
                    }
                </p>
                <p class="text-muted small">Refreshes every 10 seconds</p>
            </div>
        </div>
    </div>
</div>

@code {
    private int lowStockCount;
    private bool isPolling;
    private CancellationTokenSource? cts;

    protected override void OnInitialized()
    {
        WarehouseState.OnChanged += OnWarehouseChanged;
        AlertService.OnAlertCountChanged += OnAlertCountChanged;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPollingAsync();
        }
    }

    private async void OnWarehouseChanged()
    {
        // Restart polling for the newly selected warehouse
        await StopPollingAsync();
        await InvokeAsync(async () =>
        {
            await FetchAndPublishAsync();
            StateHasChanged();
        });
        await StartPollingAsync();
    }

    private void OnAlertCountChanged()
    {
        InvokeAsync(() =>
        {
            lowStockCount = AlertService.LastLowStockCount;
            StateHasChanged();
        });
    }

    private async Task StartPollingAsync()
    {
        cts = new CancellationTokenSource();
        isPolling = true;
        await InvokeAsync(StateHasChanged);

        _ = PollLoopAsync(cts.Token);
    }

    private async Task PollLoopAsync(CancellationToken token)
    {
        // Fetch immediately on start
        await InvokeAsync(async () =>
        {
            await FetchAndPublishAsync();
            StateHasChanged();
        });

        while (!token.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(10), token);
            }
            catch (OperationCanceledException)
            {
                break;
            }

            await InvokeAsync(async () =>
            {
                await FetchAndPublishAsync();
                StateHasChanged();
            });
        }
    }

    private async Task FetchAndPublishAsync()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        lowStockCount = count;
        AlertService.PublishAlertCount(count);
    }

    private async Task StopPollingAsync()
    {
        if (cts is not null)
        {
            await cts.CancelAsync();
            cts.Dispose();
            cts = null;
        }
        isPolling = false;
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChanged -= OnWarehouseChanged;
        AlertService.OnAlertCountChanged -= OnAlertCountChanged;
        await StopPollingAsync();
    }
}

