            @onchange="OnWarehouseChanged">
        @foreach (var wh in WarehouseState.AvailableWarehouses)
        {
            <option value="@wh.Id">@wh.Name</option>
        }
    </select>
</div>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChanged += StateHasChanged;
    }

    private void OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? WarehouseState.AvailableWarehouses[0].Id;
        var name = WarehouseState.AvailableWarehouses
            .FirstOrDefault(w => w.Id == id).Name ?? "Unknown";
        WarehouseState.SetWarehouse(id, name);
    }

    public void Dispose()
    {
        WarehouseState.OnChanged -= StateHasChanged;
    }
}

